// src/components/PanelCliente.js
import React, { useState, useEffect } from 'react';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const PanelCliente = () => {
  const [ofertas, setOfertas] = useState([]);
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);

  useEffect(() => {
    // Carga inicial de ofertas desde LocalStorage (lógica previa)
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acc = [];
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      acc = [...acc, ...ofs.map(o => ({ ...o, nombreLocal: l.nombre, localId: l.id }))];
    });
    setOfertas(acc);
  }, []);

  const handlePagoExitoso = (total) => {
    const nuevoPedido = { id: `PED-${Date.now()}`, total, fecha: new Date().toLocaleTimeString() };
    setPedidos([nuevoPedido, ...pedidos]);
    setCart([]);
    alert("¡Pago exitoso! Sigue tu pedido en el panel lateral.");
  };

  return (
    <div style={{ display: 'flex', gap: '30px', padding: '40px 5%', background: '#f8fafc' }}>
      {/* Lado Izquierdo: Ofertas */}
      <div style={{ flex: 1 }}>
        <h2>Ofertas del Día</h2>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' }}>
          {ofertas.map(o => (
            <div key={o.id} style={cardStyle}>
              <img src={o.imagen} style={{width:'100%', height:'120px', objectFit:'cover'}} alt="" />
              <div style={{padding:'10px'}}>
                <small>{o.nombreLocal}</small>
                <div style={{fontWeight:'bold'}}>{o.producto}</div>
                <div style={{color:'#e67e22'}}>${o.precioNuevo}</div>
                <button onClick={() => setCart([...cart, o])} style={btnSmall}>Agregar</button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Lado Derecho: Carrito y Seguimientos */}
      <div style={{ width: '350px' }}>
        {cart.length > 0 && <Carrito cart={cart} setCart={setCart} onCheckout={handlePagoExitoso} />}
        
        {pedidos.length > 0 && (
          <div style={{ marginTop: '30px' }}>
            <h3 style={{fontSize:'1rem', marginBottom:'15px'}}>Mis Pedidos Activos</h3>
            {pedidos.map(p => <SeguimientoPedido key={p.id} pedido={p} />)}
          </div>
        )}
      </div>
    </div>
  );
};

const cardStyle = { background: 'white', borderRadius: '12px', overflow: 'hidden', border: '1px solid #e2e8f0' };
const btnSmall = { marginTop: '10px', width: '100%', background: '#1e293b', color: 'white', border: 'none', padding: '5px', borderRadius: '5px', cursor: 'pointer' };

export default PanelCliente;
